def _service_control_configured(execution_plan):
    execution_plan = execution_plan or {}
    request_path = execution_plan.get("gpu_service_request_path") or os.environ.get(
        "BROKER_GPU_SERVICE_CONTROL_REQUEST_DIR"
    )
